sql:
SELECT patient_id, age, sex
FROM patients
WHERE age > (SELECT AVG(age) FROM patients);

SELECT 
  class AS diagnosis_status, 
  COUNT(patient_id) AS patient_count
FROM 
  diagnosis
WHERE 
  class IN ('negative', 'positive')
GROUP BY 
  class;

SELECT COUNT(*) AS Number_of_Patients
FROM medical_history
WHERE goitre = 1;

SELECT MIN(medication_start_date) 
FROM thyroid_data 
WHERE on_antithyroid_medication = 1;

SELECT COUNT(DISTINCT diagnosis.patient_id) AS hypothyroid_patient_count
FROM diagnosis
WHERE diagnosis.description = 'Hypothyroidism';

SELECT DISTINCT age
FROM patients
ORDER BY age DESC;

SELECT COUNT(DISTINCT patient_id) 
FROM query_data 
WHERE query_hypothyroid = 1;

SELECT AVG(TSH) AS average_TSH
FROM lab_results
WHERE TSH_measured = 1;

SELECT tumor, surgery_date 
FROM medical_history 
WHERE patient_id = 1024;

SELECT patient_id, on_thyroxine, query_on_thyroxine, sick, pregnant, thyroid_surgery, I131_treatment
FROM thyroid_data
WHERE on_thyroxine = 1 AND query_on_thyroxine = 1 AND pregnant = 1;

SELECT COUNT(DISTINCT patient_id) AS NumberOfPatients
FROM patients
WHERE referral_source IN ('SVI', 'SVHC');

